def pause_toggle():
    """Toggle pause state — stops the emulator so the game freezes."""
    import requests as req
    try:
        r = req.post(f"{AGENT_URL}/pause", timeout=3)
        return jsonify({"paused": True}), r.status_code
    except req.exceptions.ConnectionError:
        # Agent might not support /pause — still return ok, player will pause locally
        return jsonify({"paused": True, "note": "agent pause not available, player paused"})
    except Exception as e:
        return jsonify({"error": str(e)}), 502

